// End-to-end test for the video deblur pipeline.
//
// Generates a tiny test video from the BoofCV face image (6 frames at 6fps,
// 128x128), runs deblurVideo with worker_threads parallelism, and asserts
// the output file exists with a sane size. The deblur math is exercised by
// the per-frame tests; this test validates the ffmpeg piping, worker pool,
// frame-order reassembly, and σ-once-on-frame-0 caching.

import { beforeAll, describe, expect, it } from 'vitest';
import { spawn } from 'node:child_process';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { mkdir, stat, unlink } from 'node:fs/promises';

import { deblurVideo } from '../src/video-deblur';
import { ensureFaceJpeg } from './helpers/deblur-fixtures';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const REPO_ROOT = resolve(__dirname, '../../../..');
const SCRATCH = join(REPO_ROOT, '.qa-artifacts/scratch');
const SOURCE_IMAGE = join(SCRATCH, 'kodim17-face-gaussian-full.jpg');

async function run(cmd: string, args: string[]): Promise<void> {
  await new Promise<void>((resolveP, rejectP) => {
    const p = spawn(cmd, args, { stdio: ['ignore', 'ignore', 'pipe'] });
    let stderr = '';
    p.stderr.on('data', (d) => { stderr += d.toString(); });
    p.on('error', rejectP);
    p.on('close', (code) => {
      if (code === 0) resolveP();
      else rejectP(new Error(`${cmd} exited ${code}: ${stderr.slice(-300)}`));
    });
  });
}

describe('deblurVideo end-to-end', () => {
  beforeAll(async () => {
    await ensureFaceJpeg();
  });

  it('processes a 6-frame mp4 through the worker pool, reorders, re-encodes', async () => {
    await mkdir(SCRATCH, { recursive: true });
    const inputMp4 = join(SCRATCH, 'video-test-input.mp4');
    const outputMp4 = join(SCRATCH, 'video-test-output.mp4');

    // Build a 1-second 6fps 128x128 mp4 from the BoofCV image (6 frames total).
    await run('ffmpeg', [
      '-y', '-loop', '1', '-i', SOURCE_IMAGE,
      '-t', '1', '-r', '6',
      '-vf', 'scale=128:128',
      '-c:v', 'libx264', '-pix_fmt', 'yuv420p',
      inputMp4,
    ]);

    // Best-effort cleanup of any stale output from a previous run.
    try { await unlink(outputMp4); } catch { /* ignore */ }

    const progressUpdates: Array<{ current: number; fps: number }> = [];
    const result = await deblurVideo({
      input: inputMp4,
      output: outputMp4,
      // workers: 0 → inline mode, no worker_threads. The worker_threads path
      // requires a JS worker file (or a TS loader for the worker process,
      // which vitest does not propagate). Inline mode validates the ffmpeg
      // piping, frame splitter, σ-once-on-frame-0 caching, and reorder
      // buffer end-to-end without that loader dependency.
      workers: 0,
      options: {
        sigma: 'auto',
        channelMode: 'rgb',
        invisibleWatermark: {
          enabled: true,
          seed: 'video-e2e',
          payload: 'clip',
          strength: 0.01,
        },
      },
      onProgress: (p) => progressUpdates.push({ current: p.current, fps: p.fps }),
      progressInterval: 2,
    });

    // eslint-disable-next-line no-console
    console.log(
      `[deblurVideo] frames=${result.framesProcessed} ` +
        `σ=${result.selectedSigma.toFixed(3)} ` +
        `fps=${result.averageFps.toFixed(1)} ` +
        `elapsed=${result.elapsedMs.toFixed(0)}ms ` +
        `→ ${outputMp4}`,
    );

    expect(result.framesProcessed).toBe(6);
    expect(result.width).toBe(128);
    expect(result.height).toBe(128);
    expect(result.fps).toBeCloseTo(6, 0);
    expect(result.selectedSigma).toBeGreaterThan(0);
    expect(Number.isFinite(result.selectedSigma)).toBe(true);
    expect(result.averageFps).toBeGreaterThan(0);

    const outputStats = await stat(outputMp4);
    expect(outputStats.size).toBeGreaterThan(1024); // non-trivial mp4
  }, 180_000);
});
